sys_variable_value.value:
(function(outputs, steps, stepResult, assertEqual)
{
	var test = new x_snc_devtools.TestAPI(outputs, steps, stepResult, assertEqual);
	
	test.SetResult(true);

	var testdata = new TestDataAPI('ATF.DEVTOOLS');

	testdata.CreateUser('CALLER',[]);
	testdata.CreateUser('REQUESTER',[]);
	testdata.CreateUser('OPENER',['itil']);
	testdata.CreateUser('APPROVER',['approver']);
	testdata.CreateGroup('TEAM_1',['OPENER']);
	
	testdata.CreateIncident('INCIDENT_1','OPENER','CALLER','TEAM_1');
	testdata.CreateIncidentTask('INCIDENT_1','TASK_1','OPENER','TEAM_1');
	
	testdata.CreateChangeRequest('CHANGE_REQUEST_1','OPENER','REQUESTER','TEAM_1');
	testdata.CreateChangeTask('CHANGE_REQUEST_1','TASK_1','OPENER','TEAM_1');
	
	testdata.CreateProblem('PROBLEM_1','OPENER','TEAM_1');
	testdata.CreateProblemTask('PROBLEM_1','TASK_1','OPENER','TEAM_1');
	
	var strRequestSysId = testdata.CreateRequest('REQUEST_1','OPENER','REQUESTER','TEAM_1');
	var strRequestItemSysId = testdata.CreateRequestItem('REQUEST_ITEM_1',strRequestSysId,null,'OPENER');
	testdata.CreateRequestTask('REQUEST_TASK_1',strRequestItemSysId,'OPENER');

	test.Log(RenderValue(testdata.GetAllData()));

	test.TestCase_RecordQuery('sys_user', { user_name: 'test.atf.devtools.does_not_exist'}, false);

	test.TestCase_RecordQuery('sys_user', { user_name: 'test.atf.devtools.caller'}, true);

	test.TestCase_RecordQuery('sys_user', { user_name: 'test.atf.devtools.requester'}, true);

	test.TestCase_RecordQuery('sys_user', { user_name: 'test.atf.devtools.opener'}, true);
	test.TestCase_RecordQuery('sys_user_has_role',
		{
			user: GetUserRecord('test.atf.devtools.opener').sys_id,
			role: GetRoleRecord('itil').sys_id
		}, true);

	test.TestCase_RecordQuery('sys_user_group', { name: 'Test ATF.DEVTOOLS TEAM_1'}, true);
	test.TestCase_RecordQuery('sys_user_grmember',
		{
			user: GetUserRecord('test.atf.devtools.opener').sys_id,
			group: GetGroupRecord(testdata.MakeName('TEAM_1')).sys_id
		}, true);	

	test.TestCase_RecordQuery('incident',
		{
			short_description: testdata.MakeName('INCIDENT_1'),
			opened_by: GetUserRecord('test.atf.devtools.opener').sys_id,
			caller: GetUserRecord('test.atf.devtools.caller').sys_id,
			assignment_group: GetGroupRecord(testdata.MakeName('TEAM_1')).sys_id
		}, true);	

	
	test.TestCase_RecordQuery('incident_task',
		{
			short_description: testdata.MakeName('INCIDENT_1 - TASK_1'),
			opened_by: GetUserRecord('test.atf.devtools.opener').sys_id,
			assignment_group: GetGroupRecord(testdata.MakeName('TEAM_1')).sys_id
		}, true);

	test.TestCase_RecordQuery('change_task',
		{
			short_description: testdata.MakeName('CHANGE_REQUEST_1 - TASK_1'),
			opened_by: GetUserRecord('test.atf.devtools.opener').sys_id,
			assignment_group: GetGroupRecord(testdata.MakeName('TEAM_1')).sys_id
		}, true);

	test.TestCase_RecordQuery('problem',
		{
			short_description: testdata.MakeName('PROBLEM_1'),
			opened_by: GetUserRecord('test.atf.devtools.opener').sys_id,
			assignment_group: GetGroupRecord(testdata.MakeName('TEAM_1')).sys_id
		}, true);

	test.TestCase_RecordQuery('problem_task',
		{
			short_description: testdata.MakeName('PROBLEM_1 - TASK_1'),
			opened_by: GetUserRecord('test.atf.devtools.opener').sys_id,
			assignment_group: GetGroupRecord(testdata.MakeName('TEAM_1')).sys_id
		}, true);

	test.TestCase_RecordQuery('sc_request',
		{
			short_description: testdata.MakeName('REQUEST_1'),
			opened_by: GetUserRecord('test.atf.devtools.opener').sys_id,
			requested_for: GetUserRecord('test.atf.devtools.requester').sys_id,
			assignment_group: GetGroupRecord(testdata.MakeName('TEAM_1')).sys_id
		}, true);

	test.TestCase_RecordQuery('sc_req_item',
		{
			short_description: testdata.MakeName('REQUEST_ITEM_1'), 
			opened_by: GetUserRecord('test.atf.devtools.opener').sys_id
		}, true);

	test.TestCase_RecordQuery('sc_task',
		{
			short_description: testdata.MakeName('REQUEST_TASK_1'),
			opened_by: GetUserRecord('test.atf.devtools.opener').sys_id,
			request_item: strRequestItemSysId
		}, true);


	return test.GetResult();
	
})(outputs, steps, stepResult, assertEqual);
